// parse_news — Filtra y normaliza noticias de los 3 RSS
const keywords = [
  'comercio local', 'pyme', 'autónomo', 'subvención', 'digitalización',
  'hostelería', 'comercio minorista', 'iva', 'seguridad social',
  'licencia apertura', 'kit digital', 'empleo', 'inflación',
  'turismo', 'consumo', 'alquiler', 'energía', 'impuesto'
];

function parseRSSItems(xmlText, sourceName) {
  const items = [];
  // Match <item>...</item> blocks
  const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let match;
  while ((match = itemRegex.exec(xmlText)) !== null) {
    const block = match[1];
    const title = (block.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s) || [])[1] || '';
    const link = (block.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s) || [])[1] || '';
    const description = (block.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s) || [])[1] || '';
    const pubDate = (block.match(/<pubDate[^>]*>(.*?)<\/pubDate>/s) || [])[1] || '';
    items.push({ title: title.trim(), link: link.trim(), description: description.trim(), pubDate: pubDate.trim(), source: sourceName });
  }
  return items;
}

function scoreRelevance(title, description) {
  const text = (title + ' ' + description).toLowerCase();
  let score = 0;
  for (const kw of keywords) {
    if (text.includes(kw)) score += 3;
  }
  return Math.min(score, 10);
}

function stripHTML(str) {
  return str.replace(/<[^>]*>/g, '').replace(/&[a-z]+;/gi, ' ').trim();
}

// Get RSS inputs from the 3 feeds
const input0 = $input.all();
const allRawItems = [];

for (const item of input0) {
  const data = item.json.data || item.json.body || item.json;
  const text = typeof data === 'string' ? data : JSON.stringify(data);

  let sourceName = 'Desconocido';
  if (text.includes('elpais.com')) sourceName = 'El País';
  else if (text.includes('europapress')) sourceName = 'Europa Press';
  else if (text.includes('cincodias')) sourceName = 'Cinco Días';

  allRawItems.push(...parseRSSItems(text, sourceName));
}

// Filter by relevance
const news = allRawItems
  .map(item => {
    const relevance = scoreRelevance(item.title, item.description);
    return {
      id: 'news_' + Buffer.from(item.link || item.title).toString('base64').slice(0, 12),
      title: stripHTML(item.title),
      summary: stripHTML(item.description).slice(0, 300),
      source: item.source,
      url: item.link,
      date: item.pubDate ? new Date(item.pubDate).toISOString().split('T')[0] : new Date().toISOString().split('T')[0],
      category: 'noticias',
      relevance,
      tags: keywords.filter(kw => (item.title + ' ' + item.description).toLowerCase().includes(kw))
    };
  })
  .filter(n => n.relevance >= 3)
  .sort((a, b) => b.relevance - a.relevance)
  .slice(0, 15);

return [{ json: { news } }];

// parse_ayudas — Filtra y normaliza ayudas del BOE RSS
const keywords = [
  'pyme', 'comercio', 'digitalización', 'kit digital', 'autónomo',
  'empleo', 'formación', 'subvención', 'ayuda', 'bonificación',
  'pequeña empresa', 'microempresa', 'hostelería', 'turismo'
];

function parseRSSItems(xmlText) {
  const items = [];
  const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let match;
  while ((match = itemRegex.exec(xmlText)) !== null) {
    const block = match[1];
    const title = (block.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s) || [])[1] || '';
    const link = (block.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s) || [])[1] || '';
    const description = (block.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s) || [])[1] || '';
    const pubDate = (block.match(/<pubDate[^>]*>(.*?)<\/pubDate>/s) || [])[1] || '';
    items.push({ title: title.trim(), link: link.trim(), description: description.trim(), pubDate: pubDate.trim() });
  }
  return items;
}

function stripHTML(str) {
  return str.replace(/<[^>]*>/g, '').replace(/&[a-z]+;/gi, ' ').trim();
}

function classifyType(title, description) {
  const text = (title + ' ' + description).toLowerCase();
  if (text.includes('subvención') || text.includes('subvencion')) return 'subvención';
  if (text.includes('bonificación') || text.includes('bonificacion')) return 'bonificación';
  if (text.includes('formación') || text.includes('formacion')) return 'formación';
  return 'ayuda';
}

const input0 = $input.all();
let xmlText = '';
for (const item of input0) {
  const data = item.json.data || item.json.body || item.json;
  xmlText += typeof data === 'string' ? data : JSON.stringify(data);
}

const rawItems = parseRSSItems(xmlText);

const subsidies = [];
const regulations = [];

for (const item of rawItems) {
  const text = (item.title + ' ' + item.description).toLowerCase();
  const isRelevant = keywords.some(kw => text.includes(kw));
  if (!isRelevant) continue;

  const cleanTitle = stripHTML(item.title);
  const cleanDesc = stripHTML(item.description);

  // Detect if it's a regulation or a subsidy/aid
  if (text.includes('normativa') || text.includes('reglamento') || text.includes('obligación') || text.includes('ley ')) {
    regulations.push({
      id: 'reg_' + Buffer.from(item.link || item.title).toString('base64').slice(0, 12),
      title: cleanTitle,
      type: 'normativa',
      summary: cleanDesc.slice(0, 300),
      url: item.link,
      impact: text.includes('obligat') || text.includes('sanción') ? 'high' : 'medium',
      action_required: 'Revisar requisitos y plazos de cumplimiento'
    });
  } else {
    subsidies.push({
      id: 'sub_' + Buffer.from(item.link || item.title).toString('base64').slice(0, 12),
      title: cleanTitle,
      type: classifyType(item.title, item.description),
      amount_range: '',
      deadline: '',
      target: 'Pymes y autónomos',
      url: item.link,
      status: 'abierta'
    });
  }
}

return [{ json: { subsidies: subsidies.slice(0, 10), regulations: regulations.slice(0, 10) } }];

// build_radar_output — Combina noticias y ayudas en un objeto radar
const items = $input.all();

let news = [];
let subsidies = [];
let regulations = [];

for (const item of items) {
  if (item.json.news) news = item.json.news;
  if (item.json.subsidies) subsidies = item.json.subsidies;
  if (item.json.regulations) regulations = item.json.regulations;
}

return [{
  json: {
    radar: {
      news,
      regulations,
      subsidies,
      competitor_signals: [],
      local_events: []
    }
  }
}];

// analyze_reviews_basic — Analiza reseñas de Google Places (new API)
const placeData = $input.first().json;

const reviews = placeData.reviews || [];
const currentRating = placeData.rating || 0;
const totalReviews = placeData.userRatingCount || 0;

// Theme keywords
const themeKeywords = {
  espera: ['espera', 'tardaron', 'lento', 'rápido', 'rapidez', 'demora'],
  trato: ['trato', 'amable', 'simpático', 'maleducado', 'atención', 'servicio'],
  precio: ['precio', 'caro', 'barato', 'económico', 'relación calidad'],
  limpieza: ['limpio', 'sucio', 'limpieza', 'higiene'],
  calidad: ['calidad', 'bueno', 'malo', 'fresco', 'rico', 'delicioso', 'mediocre'],
  ambiente: ['ambiente', 'acogedor', 'ruidoso', 'tranquilo', 'decoración'],
};

function detectThemes(text) {
  if (!text) return [];
  const lower = text.toLowerCase();
  const found = [];
  for (const [theme, kws] of Object.entries(themeKeywords)) {
    if (kws.some(kw => lower.includes(kw))) found.push(theme);
  }
  return found;
}

function generateResponse(review) {
  const name = review.authorAttribution?.displayName || 'cliente';
  const rating = review.rating || 0;
  if (rating <= 2) {
    return `Estimado/a ${name}, lamentamos que su experiencia no haya sido satisfactoria. Nos gustaría conocer más detalles para poder mejorar. ¿Podría contactarnos directamente? Estamos comprometidos con ofrecer el mejor servicio.`;
  }
  if (rating === 3) {
    return `Gracias por su visita, ${name}. Tomamos nota de su valoración y trabajaremos para mejorar su próxima experiencia.`;
  }
  return null;
}

const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

let positive = 0, neutral = 0, negative = 0;
const urgentReviews = [];
const allThemes = [];

for (const review of reviews) {
  const rating = review.rating || 3;
  if (rating >= 4) positive++;
  else if (rating === 3) neutral++;
  else negative++;

  const themes = detectThemes(review.text?.text || review.originalText?.text || '');
  allThemes.push(...themes);

  // Urgent: negative + recent
  if (rating <= 2) {
    const publishTime = review.publishTime ? new Date(review.publishTime) : null;
    const isRecent = publishTime ? publishTime >= sevenDaysAgo : false;

    urgentReviews.push({
      author: review.authorAttribution?.displayName || 'Anónimo',
      rating,
      text: (review.text?.text || review.originalText?.text || '').slice(0, 500),
      date: review.publishTime || null,
      themes,
      responded: false,
      recent: isRecent,
      suggested_response: generateResponse(review)
    });
  }
}

// Count themes
const themeCounts = {};
for (const t of allThemes) {
  themeCounts[t] = (themeCounts[t] || 0) + 1;
}
const recurringThemes = Object.entries(themeCounts)
  .filter(([, c]) => c >= 2)
  .sort((a, b) => b[1] - a[1])
  .map(([t]) => t);

return [{
  json: {
    reputation: {
      reviews: {
        current_rating: currentRating,
        total_reviews: totalReviews,
        new_reviews_count: reviews.length,
        sentiment_breakdown: { positive, neutral, negative },
        recurring_themes: recurringThemes,
        urgent: urgentReviews.slice(0, 5),
        trend: positive > negative ? 'improving' : negative > positive ? 'declining' : 'stable'
      }
    }
  }
}];

// generate_marketing_ideas — Genera ideas de marketing basadas en calendario y tipo de negocio
const config = $node['Get Config'].json;
const businessType = (config.business_type || 'comercio').toLowerCase();
const city = config.city || 'Madrid';
const businessName = config.business_name || 'Mi Negocio';

const now = new Date();
const dayOfWeek = now.getDay(); // 0=Sun
const month = now.getMonth() + 1;
const day = now.getDate();

// Calendario comercial España
const upcomingDates = [];
const campaigns = [];

// Check notable dates in the next 30 days
const dates30 = [];
for (let i = 0; i < 30; i++) {
  const d = new Date(now.getTime() + i * 86400000);
  dates30.push({ date: d, m: d.getMonth() + 1, d: d.getDate(), dow: d.getDay() });
}

const calendar = [
  { m: 1, d: 6, name: 'Reyes', applicable: ['tienda', 'comercio'] },
  { m: 2, d: 14, name: 'San Valentín', applicable: ['restaurante', 'bar', 'estética', 'peluquería', 'floristería'] },
  { m: 3, d: 8, name: 'Día de la Mujer', applicable: ['estética', 'peluquería'] },
  { m: 3, d: 19, name: 'Día del Padre', applicable: ['tienda', 'restaurante', 'bar', 'peluquería'] },
  { m: 5, d: 1, name: 'Día del Trabajador', applicable: ['todos'] },
  { m: 5, d: 4, name: 'Día de la Madre', applicable: ['tienda', 'restaurante', 'estética', 'peluquería', 'floristería'] },
  { m: 6, d: 21, name: 'Inicio del Verano', applicable: ['todos'] },
  { m: 9, d: 1, name: 'Vuelta al cole', applicable: ['tienda', 'peluquería'] },
  { m: 10, d: 31, name: 'Halloween', applicable: ['bar', 'restaurante', 'tienda'] },
  { m: 11, d: 25, name: 'Black Friday', applicable: ['todos'] },
  { m: 12, d: 25, name: 'Navidad', applicable: ['todos'] },
  { m: 12, d: 31, name: 'Nochevieja', applicable: ['restaurante', 'bar'] },
];

for (const entry of calendar) {
  for (const d of dates30) {
    if (d.m === entry.m && d.d === entry.d) {
      const isApplicable = entry.applicable.includes('todos') || entry.applicable.some(t => businessType.includes(t));
      if (isApplicable) {
        const dateStr = `${d.date.getFullYear()}-${String(d.m).padStart(2,'0')}-${String(d.d).padStart(2,'0')}`;
        upcomingDates.push({ name: entry.name, date: dateStr });
        campaigns.push({
          title: `Campaña ${entry.name}`,
          type: 'promotion',
          channel: ['whatsapp', 'instagram'],
          target_audience: 'clientes_recurrentes',
          suggested_date: dateStr,
          message_draft: `¡${entry.name} se acerca! En ${businessName} tenemos algo especial preparado para ti. ¡No te lo pierdas!`,
          reason: `Fecha señalada: ${entry.name}`
        });
      }
    }
  }
}

// Día valle (martes/miércoles para hostelería)
if (['bar', 'restaurante', 'cafetería', 'café'].some(t => businessType.includes(t))) {
  const nextTuesday = dates30.find(d => d.dow === 2);
  if (nextTuesday) {
    const dateStr = nextTuesday.date.toISOString().split('T')[0];
    campaigns.push({
      title: 'Promo día valle — Martes especial',
      type: 'promotion',
      channel: ['whatsapp', 'instagram'],
      target_audience: 'clientes_recurrentes',
      suggested_date: dateStr,
      message_draft: `¡Este martes en ${businessName} tenemos oferta especial! Ven a disfrutar de nuestro menú/promoción exclusiva de entre semana.`,
      reason: 'Martes detectado como día de baja afluencia en hostelería'
    });
  }
}

// Generic seasonal idea
let seasonalIdea = '';
if (month >= 6 && month <= 8) seasonalIdea = 'Campaña de verano: terraza, refrescos, horario extendido';
else if (month >= 11 || month <= 1) seasonalIdea = 'Campaña navideña: cestas, menús especiales, tarjetas regalo';
else if (month >= 3 && month <= 5) seasonalIdea = 'Campaña de primavera: renovación, escaparates, productos de temporada';
else seasonalIdea = 'Campaña de otoño: vuelta a la rutina, ofertas de reenganche';

if (campaigns.length === 0) {
  campaigns.push({
    title: seasonalIdea,
    type: 'content',
    channel: ['instagram'],
    target_audience: 'todos',
    suggested_date: dates30[3]?.date.toISOString().split('T')[0] || '',
    message_draft: `¡Novedades en ${businessName}! Ven a descubrir lo que tenemos preparado esta temporada.`,
    reason: 'No hay fechas señaladas próximas — se sugiere campaña estacional'
  });
}

return [{
  json: {
    campaigns,
    upcoming_dates: upcomingDates
  }
}];

// build_reputation_output — Combina reviews + marketing
const items = $input.all();

let reputation = { reviews: {} };
let campaigns = [];

for (const item of items) {
  if (item.json.reputation) reputation = item.json.reputation;
  if (item.json.campaigns) campaigns = item.json.campaigns;
}

reputation.campaigns = campaigns;

return [{ json: { reputation } }];

// build_payload — Ensambla el payload final para /api/agent/ingest
const items = $input.all();
const config = $node['Get Config'].json;

let radar = { news: [], regulations: [], subsidies: [], competitor_signals: [], local_events: [] };
let reputation = { reviews: {}, campaigns: [] };

for (const item of items) {
  if (item.json.radar) {
    radar = { ...radar, ...item.json.radar };
  }
  if (item.json.reputation) {
    reputation = { ...reputation, ...item.json.reputation };
  }
}

// Build daily summary
const newsCount = (radar.news || []).length;
const subsidyCount = (radar.subsidies || []).length;
const regCount = (radar.regulations || []).length;
const urgentReviews = reputation.reviews?.urgent?.length || 0;
const campaignCount = (reputation.campaigns || []).length;

const opportunities = subsidyCount + campaignCount;
const risks = regCount + urgentReviews;

let headline = `Hoy tienes ${newsCount} noticias relevantes`;
if (subsidyCount > 0) headline += `, ${subsidyCount} ayudas disponibles`;
if (urgentReviews > 0) headline += `, ${urgentReviews} reseñas que requieren atención`;
headline += '.';

const priorityActions = [];
if (urgentReviews > 0) {
  priorityActions.push(`Responder a ${urgentReviews} reseña(s) negativa(s) urgentes`);
}
if (subsidyCount > 0) {
  priorityActions.push(`Revisar ${subsidyCount} ayuda(s)/subvención(es) disponibles`);
}
if (regCount > 0) {
  priorityActions.push(`Revisar ${regCount} cambio(s) normativo(s) que pueden afectarte`);
}
if (campaignCount > 0) {
  priorityActions.push(`Considerar ${campaignCount} idea(s) de campaña de marketing`);
}

const score = Math.min(100, 40 + newsCount * 3 + subsidyCount * 8 + campaignCount * 5 - urgentReviews * 10 - regCount * 5);

const payload = {
  user_id: config.user_id,
  agent: 'comercio_local',
  version: '1.0',
  business_id: config.business_id || null,
  timestamp: new Date().toISOString(),

  daily_summary: {
    headline,
    priority_actions: priorityActions,
    opportunities_count: opportunities,
    risks_count: risks,
    score: Math.max(0, score)
  },

  radar,
  reputation
};

return [{ json: payload }];
